class UserControllerTest extends TestCase
{
    use RefreshDatabase;

    public function test_can_create_user(): void
    {
        Mail::fake();

        $response = $this->postJson('/api/v1/users', [
            'name' => 'John Doe',
            'email' => 'john@example.com',
            'password' => 'password123',
        ]);

        $response->assertCreated()
            ->assertJsonPath('data.name', 'John Doe')
            ->assertJsonPath('data.email', 'john@example.com');

        $this->assertDatabaseHas('users', ['email' => 'john@example.com']);
        Mail::assertSent(WelcomeMail::class, fn($m) => $m->hasTo('john@example.com'));
    }

    public function test_create_user_validates_email(): void
    {
        $response = $this->postJson('/api/v1/users', [
            'name' => 'John', 'email' => 'not-an-email', 'password' => 'pass',
        ]);
        $response->assertUnprocessable()
            ->assertJsonValidationErrors(['email']);
    }

    public function test_create_user_requires_auth(): void
    {
        $response = $this->postJson('/api/v1/users', ['name' => 'X']);
        $response->assertUnauthorized();
    }
}

class UserServiceTest extends TestCase
{
    use RefreshDatabase;

    private UserService $service;

    protected function setUp(): void
    {
        parent::setUp();
        $this->service = new UserService(new UserRepository(new User()));
    }

    public function test_create_hashes_password(): void
    {
        $user = $this->service->create([
            'name' => 'John',
            'email' => 'john@example.com',
            'password' => 'plaintext',
        ]);

        $this->assertNotEquals('plaintext', $user->password);
        $this->assertTrue(Hash::check('plaintext', $user->password));
    }

    public function test_create_fires_event(): void
    {
        Event::fake();

        $this->service->create([
            'name' => 'John',
            'email' => 'john@example.com',
            'password' => 'password',
        ]);

        Event::assertDispatched(UserCreated::class,
            fn($e) => $e->user->email === 'john@example.com');
    }
}
